class Solution:
    def validateCoupons(self, code, businessLine, isActive):
        order = ['electronics', 'grocery', 'pharmacy', 'restaurant']
        allowed = set(order)
        valid = []
        for c, b, a in zip(code, businessLine, isActive):
            if not a:
                continue
            if b not in allowed:
                continue
            if c == '':
                continue
            ok = True
            for ch in c:
                if not (ch.isalnum() or ch == '_'):
                    ok = False
                    break
            if not ok:
                continue
            valid.append((b, c))
        result = []
        for cat in order:
            codes = sorted(cc for bb, cc in valid if bb == cat)
            result.extend(codes)
        return result

