var validateCoupons = function(code, businessLine, isActive) {
    const rank = { electronics: 0, grocery: 1, pharmacy: 2, restaurant: 3 };
    const re = /^[A-Za-z0-9_]+$/;
    const kept = [];
    for (let i = 0; i < code.length; i++) {
        const c = code[i], b = businessLine[i], a = isActive[i];
        if (!a) continue;
        if (!(b in rank)) continue;
        if (c.length === 0 || !re.test(c)) continue;
        kept.push([rank[b], c]);
    }
    kept.sort((x, y) => x[0] !== y[0] ? x[0] - y[0] : (x[1] < y[1] ? -1 : x[1] > y[1] ? 1 : 0));
    return kept.map(p => p[1]);
};
